	 *
	 * @return futures representing async startup work
	 */
	List<Future<Boolean>> onStartup();

	/**
	 * Sort order for startup, default 100.
	 *
	 * @return the sort order
	 */
	@Override
	default Integer sortOrder() {
		return 100;
	}


}

